-- Quiz Questions - Module m1 (10 questions)
INSERT INTO quiz_questions (id, module_id, question, options, correct_index, explanation, sort_order) VALUES
('q1-m1', 'm1', 'Qual setor NAO e impactado significativamente por TI?', '["Saude","Agricultura","Financas","Nenhum — todos sao impactados"]'::jsonb, 3, 'Todos os setores da economia sao transformados pela tecnologia da informacao.', 0),
('q2-m1', 'm1', 'O que diferencia um desenvolvedor front-end de um back-end?', '["Front-end trabalha com servidores","Back-end cria interfaces visuais","Front-end cria a interface que o usuario ve","Nao ha diferenca"]'::jsonb, 2, 'O front-end e responsavel pela interface do usuario, enquanto o back-end cuida da logica e servidores.', 1),
('q3-m1', 'm1', 'Qual habilidade comportamental e mais valorizada em TI?', '["Memorizar codigos","Trabalho isolado","Resolucao de problemas","Velocidade de digitacao"]'::jsonb, 2, 'Saber decompor e resolver problemas e a habilidade mais buscada por recrutadores.', 2),
('q4-m1', 'm1', 'O que significa a sigla TI?', '["Tecnologia Industrial","Tecnologia da Informacao","Trabalho Integrado","Tecnica de Inovacao"]'::jsonb, 1, 'TI significa Tecnologia da Informacao.', 3),
('q5-m1', 'm1', 'Qual afirmacao sobre o mercado de TI e verdadeira?', '["Ha mais profissionais do que vagas","Salarios sao geralmente baixos","Existem mais vagas do que profissionais qualificados","Trabalho remoto nao e comum"]'::jsonb, 2, 'O deficit de profissionais qualificados e uma realidade global no setor de TI.', 4),
('q6-m1', 'm1', 'O que faz um profissional de DevOps?', '["Cria interfaces de usuario","Conecta desenvolvimento e operacoes para entregas rapidas","Analisa dados de marketing","Gerencia equipes de vendas"]'::jsonb, 1, 'DevOps integra desenvolvimento e operacoes para melhorar a velocidade e confiabilidade das entregas.', 5),
('q7-m1', 'm1', 'Qual e uma porta de entrada popular para iniciar em TI?', '["Seguranca da informacao avancada","Gestao de projetos","Desenvolvimento front-end","Engenharia de dados"]'::jsonb, 2, 'Front-end e acessivel para iniciantes e permite criar projetos visiveis rapidamente.', 6),
('q8-m1', 'm1', 'Git e uma ferramenta usada para:', '["Design de interfaces","Controle de versao de codigo","Gerenciamento de emails","Criacao de bancos de dados"]'::jsonb, 1, 'Git e o sistema de controle de versao mais usado por desenvolvedores.', 7),
('q9-m1', 'm1', 'O que e uma fintech?', '["Uma fazenda tecnologica","Uma empresa de tecnologia financeira","Um tipo de hardware","Uma linguagem de programacao"]'::jsonb, 1, 'Fintechs sao empresas que usam tecnologia para inovar em servicos financeiros.', 8),
('q10-m1', 'm1', 'Qual combinacao traz mais oportunidades no mercado?', '["Apenas habilidades tecnicas","Apenas habilidades comportamentais","Habilidades tecnicas + comunicacao + adaptacao","Apenas certificacoes"]'::jsonb, 2, 'A combinacao de hard skills com soft skills e o que abre as melhores portas no mercado.', 9);

-- Generic quiz questions for other modules (2 per module)
INSERT INTO quiz_questions (id, module_id, question, options, correct_index, explanation, sort_order) VALUES
('q1-m2', 'm2', 'Qual e a principal responsabilidade de um desenvolvedor front-end?', '["Gerenciar servidores","Criar a interface do usuario","Analisar dados","Gerenciar projetos"]'::jsonb, 1, 'O front-end e responsavel por criar a interface que o usuario ve e interage.', 0),
('q2-m2', 'm2', 'O que e uma API?', '["Uma linguagem de programacao","Uma interface para comunicacao entre sistemas","Um tipo de banco de dados","Um framework CSS"]'::jsonb, 1, 'API (Application Programming Interface) permite que diferentes sistemas se comuniquem.', 1),
('q1-m3', 'm3', 'Qual a diferenca principal entre UX e UI?', '["Nao ha diferenca","UX foca na experiencia, UI no visual","UX e para mobile, UI para web","UX e mais importante que UI"]'::jsonb, 1, 'UX (User Experience) foca na experiencia geral, UI (User Interface) foca no design visual.', 0),
('q2-m3', 'm3', 'Qual ferramenta e mais usada por designers de interface?', '["Excel","Figma","Word","PowerPoint"]'::jsonb, 1, 'Figma e a ferramenta mais popular para design de interfaces.', 1),
('q1-m4', 'm4', 'O que faz um cientista de dados?', '["Cria interfaces","Analisa dados para gerar insights","Gerencia redes","Vende software"]'::jsonb, 1, 'Cientistas de dados analisam dados complexos para gerar insights que apoiam decisoes.', 0),
('q2-m4', 'm4', 'Qual linguagem e mais usada em ciencia de dados?', '["Java","C++","Python","Swift"]'::jsonb, 2, 'Python e a linguagem mais popular em ciencia de dados por sua simplicidade e bibliotecas.', 1),
('q1-m5', 'm5', 'O que significa CI/CD?', '["Codigo Integrado/Codigo Distribuido","Integracao Continua/Entrega Continua","Computacao Inteligente/Cloud Digital","Controle Interno/Controle de Deploy"]'::jsonb, 1, 'CI/CD significa Continuous Integration/Continuous Delivery.', 0),
('q2-m5', 'm5', 'Qual o papel principal do DevOps?', '["Criar interfaces bonitas","Integrar dev e operacoes para entregas rapidas","Gerenciar equipes de vendas","Analisar metricas de marketing"]'::jsonb, 1, 'DevOps integra desenvolvimento e operacoes para entregas mais rapidas e confiaveis.', 1),
('q1-m6', 'm6', 'O que e phishing?', '["Um tipo de programacao","Um ataque que tenta enganar o usuario","Um protocolo de rede","Um tipo de servidor"]'::jsonb, 1, 'Phishing e um ataque de engenharia social que tenta enganar usuarios para roubar dados.', 0),
('q2-m6', 'm6', 'Qual e a melhor pratica para senhas?', '["Usar a mesma senha em tudo","Senhas curtas e simples","Senhas longas e unicas por servico","Anotar senhas em papel"]'::jsonb, 2, 'Senhas longas, unicas e gerenciadas por um password manager sao a melhor pratica.', 1),
('q1-m7', 'm7', 'O que faz um Product Manager?', '["Programa sistemas","Define a estrategia e prioridades do produto","Gerencia a infraestrutura","Cria designs visuais"]'::jsonb, 1, 'O PM define visao, estrategia e prioridades do produto.', 0),
('q2-m7', 'm7', 'O que sao metodologias ageis?', '["Formas de programar mais rapido","Abordagens iterativas de gestao de projetos","Ferramentas de design","Linguagens de programacao"]'::jsonb, 1, 'Metodologias ageis como Scrum e Kanban focam em entregas iterativas e feedback constante.', 1),
('q1-m8', 'm8', 'Qual o primeiro passo para escolher uma carreira em TI?', '["Escolher a linguagem mais popular","Fazer autoavaliacao de interesses e perfil","Buscar o maior salario","Copiar a escolha de um amigo"]'::jsonb, 1, 'Autoavaliacao ajuda a alinhar interesses pessoais com as areas de TI.', 0),
('q2-m8', 'm8', 'Por que networking e importante em TI?', '["Para conseguir senhas","Para trocar conhecimento e oportunidades","Para vender produtos","Nao e importante"]'::jsonb, 1, 'Networking permite trocar conhecimento, descobrir vagas e acelerar o crescimento profissional.', 1),
('q1-m9', 'm9', 'O que e hardware?', '["Programas de computador","Componentes fisicos do computador","Uma linguagem de programacao","Um sistema operacional"]'::jsonb, 1, 'Hardware sao os componentes fisicos como processador, memoria e disco.', 0),
('q2-m9', 'm9', 'Qual a relacao entre hardware e software?', '["Sao independentes","Software controla o hardware","Hardware nao precisa de software","Sao a mesma coisa"]'::jsonb, 1, 'O software da instrucoes para o hardware executar tarefas.', 1),
('q1-m10', 'm10', 'O que e DNS?', '["Um tipo de hardware","Sistema que traduz nomes de dominio em IPs","Uma linguagem de programacao","Um navegador web"]'::jsonb, 1, 'DNS (Domain Name System) traduz nomes como google.com em enderecos IP.', 0),
('q2-m10', 'm10', 'O que significa HTTP?', '["High Tech Transfer Protocol","HyperText Transfer Protocol","Hardware Transfer Protocol","Home Technology Protocol"]'::jsonb, 1, 'HTTP e o protocolo usado para transferir paginas web.', 1),
('q1-m11', 'm11', 'O que e cloud computing?', '["Computacao em computadores locais","Uso de recursos computacionais via internet","Um tipo de hardware","Uma linguagem de programacao"]'::jsonb, 1, 'Cloud computing e o uso de recursos computacionais remotos via internet.', 0),
('q2-m11', 'm11', 'O que e SaaS?', '["Software as a Service","System as a Server","Storage as a Solution","Security as a Standard"]'::jsonb, 0, 'SaaS significa Software as a Service — software acessado pela internet sem instalacao.', 1),
('q1-m12', 'm12', 'Qual a funcao de um sistema operacional?', '["Criar paginas web","Gerenciar hardware e software do computador","Projetar interfaces","Analisar dados"]'::jsonb, 1, 'O SO gerencia os recursos de hardware e fornece uma plataforma para software rodar.', 0),
('q2-m12', 'm12', 'Qual sistema operacional e open source?', '["Windows","macOS","Linux","iOS"]'::jsonb, 2, 'Linux e o principal sistema operacional de codigo aberto.', 1),
('q1-m13', 'm13', 'O que e autenticacao de dois fatores?', '["Usar duas senhas","Verificacao com dois metodos diferentes","Login em dois dispositivos","Duas contas de email"]'::jsonb, 1, 'Autenticacao de dois fatores usa dois metodos diferentes para verificar identidade.', 0),
('q2-m13', 'm13', 'O que e engenharia social?', '["Engenharia de software","Manipulacao psicologica para obter informacoes","Um curso universitario","Programacao de redes sociais"]'::jsonb, 1, 'Engenharia social manipula pessoas para revelar informacoes confidenciais.', 1),
('q1-m14', 'm14', 'O que e um roteador?', '["Um tipo de software","Dispositivo que direciona trafego de rede","Uma linguagem de programacao","Um tipo de processador"]'::jsonb, 1, 'Roteadores direcionam pacotes de dados entre redes.', 0),
('q2-m14', 'm14', 'O que e TCP/IP?', '["Um tipo de hardware","Conjunto de protocolos de comunicacao da internet","Uma linguagem de programacao","Um sistema operacional"]'::jsonb, 1, 'TCP/IP e o conjunto de protocolos que permite a comunicacao na internet.', 1),
('q1-m15', 'm15', 'O que e uma linguagem de programacao?', '["Um idioma falado por programadores","Conjunto de instrucoes para o computador","Um tipo de hardware","Um sistema operacional"]'::jsonb, 1, 'Linguagens de programacao sao conjuntos de instrucoes que o computador entende.', 0),
('q2-m15', 'm15', 'O que e um compilador?', '["Um editor de texto","Programa que traduz codigo fonte em codigo de maquina","Um tipo de rede","Um banco de dados"]'::jsonb, 1, 'Compiladores traduzem codigo legivel em instrucoes que o computador pode executar.', 1),
('q1-m16', 'm16', 'O que e uma variavel?', '["Um tipo de hardware","Espaco na memoria para armazenar dados","Uma funcao matematica","Um tipo de rede"]'::jsonb, 1, 'Variaveis sao espacos na memoria que armazenam valores que podem mudar.', 0),
('q2-m16', 'm16', 'Qual e um tipo de dado basico?', '["Pagina web","Booleano","Roteador","Sistema operacional"]'::jsonb, 1, 'Booleano (true/false) e um dos tipos de dados fundamentais em programacao.', 1),
('q1-m17', 'm17', 'Para que serve o if/else?', '["Repetir codigo","Tomar decisoes no programa","Criar variaveis","Conectar a internet"]'::jsonb, 1, 'if/else permite que o programa tome decisoes baseadas em condicoes.', 0),
('q2-m17', 'm17', 'O que e um operador de comparacao?', '["Simbolo que soma numeros","Simbolo que compara dois valores","Tipo de variavel","Tipo de funcao"]'::jsonb, 1, 'Operadores de comparacao (==, >, <, etc) comparam valores e retornam verdadeiro/falso.', 1),
('q1-m18', 'm18', 'O que e um loop?', '["Uma variavel especial","Estrutura que repete instrucoes","Um tipo de funcao","Um operador"]'::jsonb, 1, 'Loops repetem um bloco de codigo enquanto uma condicao for verdadeira.', 0),
('q2-m18', 'm18', 'Quando usar um loop for?', '["Quando nao sabe quantas vezes repetir","Quando sabe o numero exato de repeticoes","Nunca","Apenas para strings"]'::jsonb, 1, 'O loop for e ideal quando voce sabe quantas vezes precisa repetir.', 1),
('q1-m19', 'm19', 'O que e uma funcao?', '["Um tipo de variavel","Bloco de codigo reutilizavel","Um operador","Um loop especial"]'::jsonb, 1, 'Funcoes sao blocos de codigo organizados e reutilizaveis.', 0),
('q2-m19', 'm19', 'O que e um parametro?', '["Valor fixo","Valor passado para uma funcao executar","Tipo de loop","Nome do programa"]'::jsonb, 1, 'Parametros sao valores que voce passa para funcoes para customizar seu comportamento.', 1),
('q1-m20', 'm20', 'Qual o primeiro passo para criar um algoritmo?', '["Escrever codigo imediatamente","Planejar a logica antes de programar","Escolher a linguagem mais dificil","Copiar codigo da internet"]'::jsonb, 1, 'Planejar a logica (pseudocodigo, fluxograma) antes de programar e essencial.', 0),
('q2-m20', 'm20', 'O que e debugging?', '["Criar bugs","Processo de encontrar e corrigir erros","Tipo de programacao","Tecnica de design"]'::jsonb, 1, 'Debugging e o processo de identificar e corrigir erros no codigo.', 1);

-- ============================================================
-- SkillBits: Content for lessons l6-l27 (Course c1 - Profissoes de T.I)
-- Brazilian Portuguese, no accents. Single quotes doubled in SQL.
-- ============================================================

-- Module m2: Desenvolvedor de Software
UPDATE lessons SET content = '[{"type":"heading","value":"Logica invisivel que faz tudo funcionar"},{"type":"paragraph","value":"O desenvolvedor back-end trabalha nos bastidores. Enquanto o front-end cuida do que o usuario ve e toca, o back-end processa dados, valida informacoes, conecta ao banco de dados e garante que cada acao gere o resultado correto."},{"type":"heading2","value":"O que o back-end faz"},{"type":"list","value":["Recebe requisicoes da aplicacao (front-end ou mobile)","Processa regras de negocio e validacoes","Consulta e salva dados em bancos de dados","Expone APIs para comunicacao entre sistemas","Garante seguranca, performance e escalabilidade"]},{"type":"heading2","value":"APIs: a ponte entre sistemas"},{"type":"paragraph","value":"API (Application Programming Interface) e como um garcom: voce faz um pedido, ele leva ate a cozinha (servidor) e traz a resposta. APIs REST sao o padrao mais comum — usam URLs e metodos HTTP como GET, POST, PUT e DELETE."},{"type":"code","language":"python","text":"# Exemplo: API que retorna lista de usuarios\n@app.get(\"/usuarios\")\ndef listar_usuarios():\n    return db.query(\"SELECT * FROM usuarios\")"},{"type":"heading2","value":"Linguagens populares"},{"type":"list","value":["Python: versatil, muito usado em startups e dados","Node.js (JavaScript): mesma linguagem do front-end","Java: enterprise, bancos e sistemas grandes","Go: performatico, ideal para microservicos"]},{"type":"callout","title":"Dica","text":"Comece com uma linguagem e aprofunde. Python e Node.js sao otimas para iniciantes e muito demandados no mercado."}]'::jsonb WHERE id = 'l6';

UPDATE lessons SET content = '[{"type":"heading","value":"Apps que vivem no bolso do usuario"},{"type":"paragraph","value":"Desenvolvimento mobile e a area responsavel por criar aplicativos para smartphones e tablets. E um mercado enorme: bilhoes de dispositivos no mundo e apps para tudo — banco, delivery, redes sociais, jogos."},{"type":"heading2","value":"Native vs cross-platform"},{"type":"paragraph","value":"Desenvolvimento nativo significa criar um app especifico para cada sistema: Swift/Kotlin para iOS/Android. Cross-platform usa uma base de codigo para gerar apps nas duas plataformas — React Native e Flutter sao as principais opcoes."},{"type":"list","value":["Native iOS: Swift e SwiftUI (linguagem e framework da Apple)","Native Android: Kotlin (linguagem oficial do Google)","React Native: JavaScript/TypeScript, codigo compartilhado","Flutter: linguagem Dart, interfaces fluidas e bonitas"]},{"type":"heading2","value":"Quando escolher cada abordagem"},{"type":"paragraph","value":"Native e ideal quando performance extrema ou recursos especificos da plataforma sao criticos. Cross-platform acelera desenvolvimento e reduz custos quando o app precisa estar em iOS e Android com time pequeno."},{"type":"code","language":"swift","text":"// SwiftUI: botao simples em iOS\nButton(\"Salvar\") {\n    salvarDados()\n}"},{"type":"callout","title":"Carreira","text":"Mobile e uma area com alta demanda. Se voce gosta de interfaces e experiencia do usuario, considere Swift ou Kotlin. Se prefere codigo unico, React Native ou Flutter."}]'::jsonb WHERE id = 'l7';

UPDATE lessons SET content = '[{"type":"heading","value":"Dominar front e back em uma so pessoa"},{"type":"paragraph","value":"Full stack e o desenvolvedor que atua em todas as camadas da aplicacao: front-end, back-end e, muitas vezes, banco de dados e deploy. E o generalista que entende o sistema por completo."},{"type":"heading2","value":"O que um full stack faz"},{"type":"list","value":["Implementa interfaces (HTML, CSS, JavaScript)","Desenvolve APIs e logica de servidor","Modela e consulta bancos de dados","Faz integracao entre componentes","Participa de deploy e configuracao basica"]},{"type":"heading2","value":"Vantagens e desvantagens"},{"type":"paragraph","value":"Vantagem: flexibilidade, visao holistica e capacidade de entregar produtos sozinho ou em times pequenos. Desvantagem: risco de nao se aprofundar em nenhuma area — o mercado valoriza especialistas em posicoes senior."},{"type":"heading2","value":"A realidade do mercado"},{"type":"paragraph","value":"Startups e empresas menores adoram full stacks. Grandes empresas costumam ter times especializados. A estrategia: comecar full stack para ganhar versatilidade, depois escolher uma pilha para se especializar."},{"type":"callout","title":"Mito desfeito","text":"Full stack nao e ''saber de tudo superficialmente''. E ter profundidade em front e back, com capacidade de aprender o que falta no projeto."}]'::jsonb WHERE id = 'l8';

-- Module m3: Designer de UX/UI
UPDATE lessons SET content = '[{"type":"heading","value":"Experiencia e interface: duas faces da mesma moeda"},{"type":"paragraph","value":"UX e UI sao termos que aparecem juntos, mas representam focos diferentes. UX (User Experience) cuida de como o usuario se sente e consegue atingir seus objetivos. UI (User Interface) cuida da parte visual — cores, botoes, tipografia."},{"type":"heading2","value":"UX: pesquisa e estrategia"},{"type":"list","value":["Pesquisa com usuarios: entrevistas, testes, analise de comportamento","Definicao de jornadas e fluxos de uso","Wireframes e prototipos de baixa fidelidade","Mapeamento de dores e necessidades"]},{"type":"heading2","value":"UI: visual e interacao"},{"type":"list","value":["Design visual: cores, fontes, espacamentos","Componentes clicaveis e estados (hover, active, disabled)","Consistencia e design systems","Acessibilidade e padroes de interacao"]},{"type":"heading2","value":"Como se complementam"},{"type":"paragraph","value":"Um produto bonito mas confuso falha. Um produto funcional mas feio desanima. UX define o que construir e como fluir; UI da forma e beleza. O ideal e ter visao das duas areas."},{"type":"callout","title":"Reflexao","text":"Voce prefere entender pessoas e processos (UX) ou criar interfaces visuais refinadas (UI)? As duas areas se cruzam, mas o ponto de partida e diferente."}]'::jsonb WHERE id = 'l9';

UPDATE lessons SET content = '[{"type":"heading","value":"As ferramentas que os designers usam no dia a dia"},{"type":"paragraph","value":"Designers de produto trabalham com ferramentas especializadas para criar interfaces, prototipos e sistemas de design. A maioria das vagas exige dominio de pelo menos uma delas."},{"type":"heading2","value":"Figma: o padrao do mercado"},{"type":"paragraph","value":"Figma e a ferramenta mais usada hoje. Funciona no navegador, permite colaboracao em tempo real e tem recursos poderosos para prototipagem, componentes e design systems. Versao gratuita disponivel."},{"type":"heading2","value":"Outras ferramentas"},{"type":"list","value":["Adobe XD: integracao com suite Adobe, prototipagem","Sketch: Mac only, popular entre designers Apple","Adobe Illustrator: icones, ilustracoes, vetores","Miro/Figma Jam: brainstorm e workshops remotas"]},{"type":"heading2","value":"Prototipagem e design systems"},{"type":"paragraph","value":"Prototipagem permite simular a experiencia antes de desenvolver. Design systems sao conjuntos de componentes e regras reutilizaveis — garantem consistencia e aceleram o trabalho de times grandes."},{"type":"callout","title":"Dica","text":"Comece pelo Figma. A curva de aprendizado e gentil e a maioria dos tutoriais e vagas de design UX/UI usam Figma."}]'::jsonb WHERE id = 'l10';

UPDATE lessons SET content = '[{"type":"heading","value":"Como mostrar seu trabalho e conseguir oportunidades"},{"type":"paragraph","value":"Para designers, portfolio e o principal diferencial na hora de ser contratado. Diferente de desenvolvedores, o que importa nao e so codigo — e a capacidade de comunicar decisoes de design e impacto."},{"type":"heading2","value":"Estruturando um portfolio"},{"type":"list","value":["Projetos reais ou estudos de caso ficticios bem documentados","Contexto: problema, publico, objetivo","Processo: pesquisa, ideacao, iteracao","Resultado: metricas, feedback, aprendizados"]},{"type":"heading2","value":"Case studies que impressionam"},{"type":"paragraph","value":"Um bom case study conta uma historia: qual era o problema, o que voce fez, por que fez assim e qual foi o resultado. Mostre raciocinio, nao so telas bonitas."},{"type":"heading2","value":"Mercado de trabalho"},{"type":"paragraph","value":"Vagas em startups, empresas de produto, agencias e consultorias. Remoto expandiu oportunidades. Salarios iniciais competitivos e crescimento rapido para quem demonstra impacto."},{"type":"callout","title":"Carreira","text":"Portfolio com 3-5 projetos bem documentados vale mais que dezenas de telas soltas. Qualidade sobre quantidade."}]'::jsonb WHERE id = 'l11';

-- Module m4: Analista e Cientista de Dados
UPDATE lessons SET content = '[{"type":"heading","value":"Transformando dados em decisoes"},{"type":"paragraph","value":"O analista de dados coleta, organiza e interpreta dados para ajudar empresas a tomar decisoes melhores. Dashboards, relatorios e metricas sao ferramentas do dia a dia."},{"type":"heading2","value":"O que um analista faz"},{"type":"list","value":["Coleta dados de diferentes fontes (banco, planilhas, APIs)","Limpa e organiza dados para analise","Cria dashboards e visualizacoes","Identifica tendencias, anomalias e insights","Comunica achados para equipes e lideranca"]},{"type":"heading2","value":"Business Intelligence"},{"type":"paragraph","value":"BI (Business Intelligence) e a pratica de transformar dados brutos em informacoes acionaveis. Ferramentas como Power BI e Tableau permitem criar paineis interativos que qualquer pessoa da empresa pode usar."},{"type":"heading2","value":"SQL: a base de tudo"},{"type":"paragraph","value":"SQL e a linguagem para consultar bancos de dados. Mesmo sem ser programador, um analista precisa saber filtrar, agrupar e cruzar dados com SELECT, WHERE, GROUP BY e JOIN."},{"type":"code","language":"sql","text":"-- Exemplo: vendas por regiao\nSELECT regiao, SUM(valor) as total\nFROM vendas\nGROUP BY regiao"},{"type":"callout","title":"Dado importante","text":"Analistas de dados estao entre os perfis mais demandados. Empresas de todos os setores precisam de pessoas que traduzam dados em decisoes."}]'::jsonb WHERE id = 'l12';

UPDATE lessons SET content = '[{"type":"heading","value":"Dados, modelos e inteligencia artificial"},{"type":"paragraph","value":"O cientista de dados vai alem da analise: cria modelos preditivos, trabalha com machine learning e aplica tecnicas estatisticas para resolver problemas complexos. E o passo seguinte na carreira de dados."},{"type":"heading2","value":"Ciencia de dados vs analise"},{"type":"paragraph","value":"Analistas respondem perguntas como ''O que aconteceu?'' e ''Por que?''. Cientistas respondem ''O que vai acontecer?'' e ''Como otimizar?'' usando modelos matematicos e algoritmos."},{"type":"heading2","value":"Machine learning na pratica"},{"type":"list","value":["Aprendizado supervisionado: prever valores ou categorias","Aprendizado nao supervisionado: encontrar padroes nos dados","Aplicacoes: recomendacao, deteccao de fraude, previsionais"]},{"type":"heading2","value":"Caminho de carreira"},{"type":"paragraph","value":"A base e solida em estatistica, programacao (Python) e SQL. Depois vem bibliotecas como Pandas, Scikit-learn e TensorFlow. Experiencia em analise de dados ajuda muito na transicao."},{"type":"callout","title":"Mito desfeito","text":"Voce nao precisa ser PhD em matematica. Ciencia de dados pratica exige logica, curiosidade e vontade de experimentar — formacao em exatas ajuda, mas nao e obrigatoria."}]'::jsonb WHERE id = 'l13';

UPDATE lessons SET content = '[{"type":"heading","value":"Stack tecnologica para trabalhar com dados"},{"type":"paragraph","value":"Profissionais de dados usam um conjunto de ferramentas e linguagens. Conhecer o ecossistema ajuda a escolher por onde comecar e qual direcao seguir."},{"type":"heading2","value":"Linguagens"},{"type":"list","value":["Python: linguagem principal para analise e ML (Pandas, NumPy, Scikit-learn)","R: estatistica e visualizacao, comum em academia","SQL: consulta a bancos, essencial para qualquer perfil"]},{"type":"heading2","value":"Ferramentas de visualizacao"},{"type":"list","value":["Tableau: dashboards interativos, muito usado em empresas","Power BI: integracao Microsoft, popular no Brasil","Excel/Google Sheets: entrada, analises rapidas, MVP de dashboards"]},{"type":"heading2","value":"Onde os dados vivem"},{"type":"paragraph","value":"Dados ficam em bancos relacionais (PostgreSQL, MySQL), data warehouses (BigQuery, Redshift) ou lakes de dados. Entender conceitos de armazenamento e consulta e fundamental."},{"type":"callout","title":"Dica","text":"Comece com Python + SQL + Excel. Com essa base voce ja consegue analisar dados reais e se candidatar a vagas de analista junior."}]'::jsonb WHERE id = 'l14';

-- Module m5: DevOps e Engenheiro de Infraestrutura
UPDATE lessons SET content = '[{"type":"heading","value":"A ponte entre desenvolvimento e operacoes"},{"type":"paragraph","value":"DevOps nao e so uma funcao — e uma cultura e conjunto de praticas que unem desenvolvimento e operacoes. O objetivo: entregar software com mais velocidade, qualidade e confiabilidade."},{"type":"heading2","value":"O papel do DevOps"},{"type":"list","value":["Automatizar processos que antes eram manuais","Garantir que o codigo chegue a producao de forma segura","Monitorar sistemas e responder a incidentes","Colaborar com devs para melhorar pipeline e infraestrutura"]},{"type":"heading2","value":"Cultura antes de ferramentas"},{"type":"paragraph","value":"DevOps exige que devs e ops trabalhem juntos, compartilhem responsabilidades e aprendam continuamente. Cultura de culpa vai contra os principios — o foco e em melhorar o sistema, nao culpar pessoas."},{"type":"heading2","value":"Responsabilidades tipicas"},{"type":"paragraph","value":"Configuracao de servidores, CI/CD, containers, monitoramento, seguranca de infraestrutura. O profissional DevOps muitas vezes tem background em desenvolvimento ou sysadmin."},{"type":"callout","title":"Reflexao","text":"Voce gosta de automatizar tarefas repetitivas e garantir que sistemas rodem 24/7? DevOps pode ser sua trilha."}]'::jsonb WHERE id = 'l15';

UPDATE lessons SET content = '[{"type":"heading","value":"Integrar, entregar e repetir"},{"type":"paragraph","value":"CI/CD (Continuous Integration / Continuous Delivery) e o coracao da automacao em DevOps. Codigo e integrado continuamente, testado automaticamente e entregue em producao de forma rapida e segura."},{"type":"heading2","value":"Continuous Integration"},{"type":"paragraph","value":"CI garante que cada alteracao no codigo seja testada assim que entra no repositorio. Builds automaticos, testes unitarios e analise de qualidade rodam em cada commit ou pull request."},{"type":"heading2","value":"Continuous Delivery"},{"type":"paragraph","value":"CD leva o codigo aprovado ate producao. Pipelines automatizados fazem deploy em ambientes de homologacao e producao, reduzindo erros humanos e tempo de entrega."},{"type":"list","value":["GitHub Actions, GitLab CI, Jenkins: orquestradores de pipeline","Testes automatizados: unitarios, integracao, e2e","Deploy em staging antes de producao"]},{"type":"code","language":"yaml","text":"# Exemplo: pipeline CI simplificado\n- run: npm test\n- run: npm run build\n- deploy: prod"},{"type":"callout","title":"Dado importante","text":"Empresas que adotam CI/CD entregam atualizacoes com frequencia muito maior e menor taxa de falhas em producao."}]'::jsonb WHERE id = 'l16';

UPDATE lessons SET content = '[{"type":"heading","value":"Nuvem, containers e infraestrutura como codigo"},{"type":"paragraph","value":"A infraestrutura moderna nao usa mais apenas servidores fisicos. Cloud, containers e automacao definem como sistemas escalam e rodam com confiabilidade."},{"type":"heading2","value":"Provedores de cloud"},{"type":"list","value":["AWS (Amazon): maior mercado, muitos servicos","Azure (Microsoft): forte em empresas Windows","GCP (Google): forte em dados e ML"]},{"type":"heading2","value":"Containers e orquestracao"},{"type":"paragraph","value":"Docker empacota aplicacoes com dependencias em containers — rodam igual em qualquer ambiente. Kubernetes orquestra containers em escala, gerenciando deploy, escalabilidade e recuperacao."},{"type":"heading2","value":"Infraestrutura como codigo"},{"type":"paragraph","value":"Terraform, CloudFormation e Pulumi permitem definir servidores, redes e banco de dados em arquivos. Infraestrutura vira codigo versionado, revisavel e reproduzivel."},{"type":"callout","title":"Carreira","text":"Certificacoes em AWS, Azure ou GCP sao um bom diferencial. Comece com conceitos de cloud e Docker antes de Kubernetes."}]'::jsonb WHERE id = 'l17';

-- Module m6: Seguranca da Informacao
UPDATE lessons SET content = '[{"type":"heading","value":"Protegendo sistemas, redes e dados"},{"type":"paragraph","value":"Profissionais de seguranca da informacao sao responsaveis por proteger ativos digitais de empresas e usuarios. E uma area em alta demanda: ataques crescentes exigem cada vez mais especialistas."},{"type":"heading2","value":"Perfis na area"},{"type":"list","value":["Analista SOC: monitora ameacas e responde a incidentes","Pentester (ethical hacker): testa vulnerabilidades por autorizacao","Auditor: verifica conformidade e politicas de seguranca","Engenheiro de seguranca: desenha e implementa controles"]},{"type":"heading2","value":"O dia a dia"},{"type":"paragraph","value":"Monitoramento de logs, analise de alertas, resposta a incidentes, testes de invasao em sistemas autorizados, treinamento de usuarios em conscientizacao e elaboracao de politicas."},{"type":"heading2","value":"Conhecimentos base"},{"type":"paragraph","value":"Rede, sistemas operacionais (especialmente Linux), fundamentos de programacao e entendimento de como aplicacoes e infraestrutura funcionam. Curiosidade e pensamento adversarial sao essenciais."},{"type":"callout","title":"Dica","text":"Comece com fundamentos de redes e Linux. Depois explore certificacoes de entrada como CompTIA Security+."}]'::jsonb WHERE id = 'l18';

UPDATE lessons SET content = '[{"type":"heading","value":"Conhecendo o inimigo para se defender"},{"type":"paragraph","value":"Para proteger sistemas, e preciso entender as ameacas. Conhecer os tipos de ataques ajuda a identificar vulnerabilidades e implementar controles adequados."},{"type":"heading2","value":"Malware e ransomwares"},{"type":"paragraph","value":"Malware sao programas maliciosos — virus, worms, trojans. Ransomware criptografa dados e exige pagamento para liberar. Backups e atualizacoes constantes sao defesas fundamentais."},{"type":"heading2","value":"Phishing e engenharia social"},{"type":"paragraph","value":"Phishing engana pessoas para revelar senhas ou clicar em links maliciosos. Engenharia social explora confianca humana — muitas brechas comecam com um email convincente, nao com codigo."},{"type":"list","value":["DDoS: sobrecarrega servicos para derrubar sites","SQL Injection: injeta codigo em consultas a banco","Man-in-the-middle: intercepta comunicacao entre partes"]},{"type":"callout","title":"Mito desfeito","text":"Seguranca nao e so firewall e antivirus. A pessoa e frequentemente o elo mais fraco — treinamento e conscientizacao fazem diferenca."}]'::jsonb WHERE id = 'l19';

UPDATE lessons SET content = '[{"type":"heading","value":"Formalizando conhecimento e crescendo na carreira"},{"type":"paragraph","value":"Certificacoes em seguranca ajudam a comprovar conhecimento e abrem portas. A area tem trilhas claras de evolucao, de analista junior ate liderenca em CISO."},{"type":"heading2","value":"Certificacoes de entrada"},{"type":"list","value":["CompTIA Security+: base ampla em seguranca","CEH (Certified Ethical Hacker): teste de invasao autorizado","Certificacoes de cloud (AWS Security, Azure Security)"]},{"type":"heading2","value":"Para quem quer se aprofundar"},{"type":"paragraph","value":"CISSP (Certified Information Systems Security Professional) e uma das mais reconhecidas para profissionais senior. Exige anos de experiencia e abrange dominios amplos de seguranca."},{"type":"heading2","value":"Progressao de carreira"},{"type":"paragraph","value":"Analista SOC junior, analista senior, engenheiro de seguranca, arquiteto de seguranca, CISO. Alternativas: consultoria, pentest especializado, forense digital."},{"type":"callout","title":"Carreira","text":"Seguranca e uma area com poucos profissionais para a demanda. Salarios competitivos e possibilidade de atuar em qualquer industria."}]'::jsonb WHERE id = 'l20';

-- Module m7: Gestao de TI e Product Manager
UPDATE lessons SET content = '[{"type":"heading","value":"Dois papais diferentes na lideranca tecnica"},{"type":"paragraph","value":"Gestor de TI e Product Manager sao funcoes distintas, mas ambas lideram esforcos relacionados a tecnologia. Entender a diferenca ajuda a escolher o caminho certo."},{"type":"heading2","value":"Gestor de TI"},{"type":"list","value":["Foco em pessoas e operacao do time tecnico","Gestao de equipe: desempenho, desenvolvimento, contratacao","Alinhamento com outros gestores e areas de negocio","Garantir entrega e qualidade do trabalho do time"]},{"type":"heading2","value":"Product Manager"},{"type":"list","value":["Foco no produto e no usuario","Define o que construir e prioriza o backlog","Pesquisa, metrics e estrategia do produto","Conecta negocio, usuario e time de desenvolvimento"]},{"type":"heading2","value":"Como se relacionam"},{"type":"paragraph","value":"PM decide o que fazer; gestor de TI (ou tech lead) garante que o time tenha condicoes de executar. Em startups, uma pessoa pode acumular funcoes; em empresas maiores, os papais se separam."},{"type":"callout","title":"Reflexao","text":"Voce prefere cuidar das pessoas e do time (gestao) ou do produto e da estrategia (PM)?"}]'::jsonb WHERE id = 'l21';

UPDATE lessons SET content = '[{"type":"heading","value":"Scrum, Kanban e praticas que agilizam o trabalho"},{"type":"paragraph","value":"Metodologias ageis sao a forma como a maioria dos times de tecnologia organiza o trabalho. Entender Scrum e Kanban e essencial para qualquer papel em produto ou desenvolvimento."},{"type":"heading2","value":"Scrum"},{"type":"list","value":["Sprints: iteracoes fixas (1-2 semanas) com meta clara","Daily standup: reuniao curta diaria de sincronizacao","Sprint planning: planejamento do que entra na sprint","Retrospectiva: melhoria continua do processo"]},{"type":"heading2","value":"Kanban"},{"type":"paragraph","value":"Kanban visualiza o fluxo de trabalho em colunas (To Do, In Progress, Done). Sem sprints fixos — trabalho flui conforme capacidade. Bom para times com demanda variavel ou manutencao."},{"type":"heading2","value":"Cerimonias comuns"},{"type":"paragraph","value":"Planning, daily, review e retrospectiva sao cerimonias tipicas. A ideia e manter ciclos curtos de feedback, entregar valor incremental e adaptar o plano conforme aprendizado."},{"type":"callout","title":"Dado importante","text":"Metodologias ageis sao uma exigencia em praticamente todas as vagas de produto e desenvolvimento. Vale a pena praticar em projetos proprios."}]'::jsonb WHERE id = 'l22';

UPDATE lessons SET content = '[{"type":"heading","value":"Do tecnico que executa ao lider que habilita"},{"type":"paragraph","value":"A transicao de desenvolvedor, designer ou analista para posicoes de lideranca exige novas habilidades. O que te fez destacar como tecnico nem sempre e o que te faz um bom lider."},{"type":"heading2","value":"O que muda na transicao"},{"type":"list","value":["Sucesso deixa de ser individual — passa a ser do time","Comunicacao e influencia ganham peso","Delegar e ensinar substituem ''fazer tudo''","Decisoes de pessoas e priorizacao entram no dia a dia"]},{"type":"heading2","value":"Habilidades para desenvolver"},{"type":"paragraph","value":"Escuta ativa, feedback construtivo, gestao de conflitos, visao estrategica. Um bom lider tecnico mantem proximidade com a tecnologia mas abre espaco para o time executar."},{"type":"heading2","value":"Nao e obrigatorio subir"},{"type":"paragraph","value":"Carreira tecnica (IC — Individual Contributor) e uma trajetoria valida. Muitos profissionais preferem aprofundar em arquitetura ou especialidade em vez de gerenciar pessoas."},{"type":"callout","title":"Dica","text":"Antes de assumir gestao, procure mentorias e leituras sobre lideranca. A transicao e um aprendizado em si."}]'::jsonb WHERE id = 'l23';

-- Module m8: Como escolher sua trilha
UPDATE lessons SET content = '[{"type":"heading","value":"Conhecer a si mesmo antes de escolher"},{"type":"paragraph","value":"Escolher uma carreira em TI pode parecer intimidante com tantas opcoes. A autoavaliacao ajuda: seus interesses, forma de trabalhar e perfil tendem a se encaixar melhor em algumas areas."},{"type":"heading2","value":"Perfis e areas"},{"type":"list","value":["Gosta de criar interfaces e ver resultado visual? Front-end, UX/UI","Prefere logica, sistemas e banco de dados? Back-end, dados","Quer resolver problemas de pessoas? UX research, Product","Gosta de infraestrutura e automatizar? DevOps, seguranca","Interesse em liderar e influenciar? Gestao, PM"]},{"type":"heading2","value":"Perguntas para refletir"},{"type":"paragraph","value":"Voce prefere trabalhar so ou em equipe? Prefere variedade ou profundidade? Gosta de comunicacao escrita ou verbal? Responder honestamente a essas perguntas ajudam a reduzir as opcoes."},{"type":"callout","title":"Reflexao","text":"Nao existe escolha errada. Voce pode comecar em uma area e mudar depois. O importante e comecar e aprender na pratica."}]'::jsonb WHERE id = 'l24';

UPDATE lessons SET content = '[{"type":"heading","value":"Rotas de aprendizado por carreira"},{"type":"paragraph","value":"Cada area tem um caminho sugerido de estudos. Conhecer o roadmap ajuda a priorizar o que aprender primeiro e evita perder tempo com coisas menos relevantes para seu objetivo."},{"type":"heading2","value":"Front-end"},{"type":"list","value":["HTML, CSS, JavaScript fundamentals","React ou Vue","Git, responsividade, acessibilidade"]},{"type":"heading2","value":"Back-end"},{"type":"list","value":["Python ou Node.js","SQL e bancos de dados","APIs REST, autenticacao"]},{"type":"heading2","value":"Dados"},{"type":"list","value":["SQL, Excel/Power BI","Python, Pandas","Estatistica basica, visualizacao"]},{"type":"heading2","value":"UX/UI e DevOps"},{"type":"paragraph","value":"UX/UI: Figma, fundamentos de design, pesquisa de usuarios. DevOps: Linux, Git, Docker, um provedor de cloud, CI/CD. Recursos gratuitos abundam — cursos, documentacao oficial e projetos praticos."},{"type":"callout","title":"Dica","text":"Roadmaps.sh e roadmap.engineer sao otimos para visualizar trilhas completas. Adapte ao seu ritmo e contexto."}]'::jsonb WHERE id = 'l25';

UPDATE lessons SET content = '[{"type":"heading","value":"Conectar, trocar e crescer com a comunidade"},{"type":"paragraph","value":"Networking em tecnologia nao e so ''pegar contatos'' — e aprender com outros, compartilhar conhecimento e se manter atualizado. Comunidades abrem portas para oportunidades e mentorias."},{"type":"heading2","value":"Onde participar"},{"type":"list","value":["Meetups e eventos locais (presenciais ou online)","Discord e Slack de comunidades tecnicas","LinkedIn: posts, comentarios, conexoes","GitHub: contribuir em projetos open source"]},{"type":"heading2","value":"Como aproveitar"},{"type":"paragraph","value":"Seja ativo: faca perguntas, responda duvidas, compartilhe seu aprendizado. Um post explicando o que voce estudou ajuda a fixar e atrai pessoas com interesses parecidos."},{"type":"heading2","value":"Beneficios reais"},{"type":"paragraph","value":"Indicacoes para vagas, feedback em projetos, parcerias para estudos em grupo. Muitas oportunidades nao aparecem em sites de emprego — surgem de contatos e reputacao."},{"type":"callout","title":"Carreira","text":"Comunidade nao e so para quando voce precisa de emprego. Invista em relacionamentos ao longo do tempo."}]'::jsonb WHERE id = 'l26';

UPDATE lessons SET content = '[{"type":"heading","value":"Colocando a mao na massa"},{"type":"paragraph","value":"Projetos praticos sao a melhor forma de aprender e demonstrar habilidades. Nada substitui construir algo do zero — e o portfolio que vai te destacar em processos seletivos."},{"type":"heading2","value":"Por que projetos importam"},{"type":"list","value":["Fixam o aprendizado na pratica","Demonstram capacidade de entregar","Servem de tema para entrevistas","Mostram iniciativa e autonomia"]},{"type":"heading2","value":"Ideias para comecar"},{"type":"list","value":["Clone de um app ou site que voce usa (simplificado)","Problema pessoal: app de lista, calculadora, dashboard","Projeto de curso com twist proprio","Contribuicao em projeto open source"]},{"type":"heading2","value":"Como comecar"},{"type":"paragraph","value":"Escolha algo pequeno que complete em alguns dias. Use tecnologias que voce esta estudando. Documente no README: o que fez, como rodar, o que aprendeu. Um projeto concluido vale mais que dez incompletos."},{"type":"callout","title":"Dica","text":"Nao espere estar ''pronto''. Comece simples e va melhorando. O primeiro projeto nao precisa ser perfeito."}]'::jsonb WHERE id = 'l27';

-- Seed content for lessons l28-l42, course c2 "Conceitos Basicos de T.I"
-- Run after seed.sql. All text in Brazilian Portuguese (no accents).

UPDATE lessons SET content = '[{"type":"heading","value":"O que e hardware"},{"type":"paragraph","value":"Hardware e tudo que voce pode tocar no computador: as pecas fisicas que fazem a maquina funcionar. Pense no hardware como o corpo do computador — ossos, musculos e orgaos que executam as tarefas."},{"type":"heading2","value":"Componentes principais"},{"type":"paragraph","value":"O processador (CPU) e o cerebro: ele executa as instrucoes e faz os calculos. A memoria RAM guarda temporariamente os dados em uso — quanto mais RAM, mais programas rodando ao mesmo tempo sem travar."},{"type":"list","value":["CPU: processa instrucoes e calculos","RAM: memoria temporaria para programas em execucao","Armazenamento: disco que guarda arquivos permanentemente (SSD ou HD)","GPU: processa graficos, jogos e edicao de video","Placa-mae: conecta todos os componentes","Perifericos: teclado, mouse, monitor — tudo que voce conecta"]},{"type":"heading2","value":"Analogia do escritorio"},{"type":"paragraph","value":"Imagine a CPU como o funcionario que trabalha. A mesa de trabalho (RAM) precisa ser grande para espalhar varios papeis. O arquivo (disco) guarda tudo que nao esta em uso. Quanto maior e mais organizado o escritorio, mais produtivo o trabalho."},{"type":"callout","title":"Dica","text":"Ao comprar um computador, priorize RAM (8 GB minimo) e um SSD em vez de HD antigo. A diferenca no dia a dia e enorme."}]'::jsonb WHERE id = 'l28';

UPDATE lessons SET content = '[{"type":"heading","value":"O que e software"},{"type":"paragraph","value":"Software sao os programas e instrucoes que fazem o hardware funcionar. Se o hardware e o corpo do computador, o software e a mente — diz o que fazer e como fazer."},{"type":"heading2","value":"Software de sistema e aplicativo"},{"type":"paragraph","value":"O sistema operacional (Windows, macOS, Linux) e o software base: gerencia o hardware e permite que outros programas rodem. Software aplicativo sao os programas que voce usa para tarefas especificas."},{"type":"list","value":["Sistema operacional: Windows, macOS, Linux, iOS, Android","Navegadores: Chrome, Firefox, Safari","Editores: Word, Google Docs","Comunicacao: WhatsApp, Zoom, Outlook","Entretenimento: Spotify, Netflix, jogos"]},{"type":"heading2","value":"Exemplos do dia a dia"},{"type":"paragraph","value":"Quando voce abre o Instagram, esta usando software aplicativo. O Instagram roda em cima do sistema operacional do seu celular, que por sua vez controla a tela, a camera e a conexao de internet. Tudo e software em camadas."},{"type":"callout","title":"Mito desfeito","text":"Software nao e so app de celular. O caixa do supermercado, o painel do carro e o controle remoto da TV rodam software — mesmo quando voce nao percebe."}]'::jsonb WHERE id = 'l29';

UPDATE lessons SET content = '[{"type":"heading","value":"Como hardware e software trabalham juntos"},{"type":"paragraph","value":"Hardware e software so funcionam bem quando trabalham em equipe. O software da as ordens; o hardware executa. Sem um, o outro nao serve para nada."},{"type":"heading2","value":"O processo de ligar o PC"},{"type":"paragraph","value":"Quando voce liga o computador, a placa-mae acorda primeiro e verifica se os componentes estao ok. Depois, o sistema operacional e carregado do disco para a RAM. Em segundos, a interface aparece e voce pode usar os programas."},{"type":"heading2","value":"Do clique ao resultado"},{"type":"paragraph","value":"Clicar em Salvar parece simples, mas por tras acontece muita coisa: o software manda a ordem de gravar, o sistema operacional coordena, e o disco recebe os dados. Drivers sao pequenos programas que traduzem ordens do software para a linguagem que cada peca de hardware entende."},{"type":"list","value":["Driver de video: faz a GPU entender o que desenhar na tela","Driver de rede: faz o PC conversar com a internet","Driver de impressora: traduz documentos para a impressora imprimir"]},{"type":"callout","title":"Curiosidade","text":"Por isso atualizar drivers pode resolver problemas como tela preta ou internet nao funcionando. Os drivers sao os interpretes entre software e hardware."}]'::jsonb WHERE id = 'l30';

UPDATE lessons SET content = '[{"type":"heading","value":"O caminho de um site ate voce"},{"type":"paragraph","value":"Quando voce digita google.com e aperta Enter, muita coisa acontece em milissegundos. O seu pedido atravessa sua rede, a internet e chega ate servidores que devolvem a pagina. Vamos desvendar essa jornada."},{"type":"heading2","value":"Passo a passo da requisicao"},{"type":"paragraph","value":"Primeiro, seu navegador precisa descobrir o endereco do Google. Ele pergunta a um servidor DNS qual e o numero (IP) do google.com. Com esse numero, o navegador envia um pedido HTTP ate um dos data centers do Google."},{"type":"list","value":["1. Voce digita a URL e aperta Enter","2. DNS traduz google.com em um endereco IP","3. O pedido passa pelo roteador da sua casa","4. Via cabo ou Wi-Fi, atravessa sua rede local","5. Sai para a internet por cabos de fibra optica","6. Pode cruzar oceanos em cabos submarinos","7. Chega ao servidor do site e recebe a resposta"]},{"type":"heading2","value":"Onde ficam os sites?"},{"type":"paragraph","value":"Sites vivem em servidores — computadores potentes em predios chamados data centers. Empresas como Google, Amazon e Facebook mantem milhares desses servidores em varios paises. Quando voce acessa um site, provavelmente esta falando com um servidor a centenas ou milhares de quilometros."},{"type":"callout","title":"Curiosidade","text":"Mais de 95% do trafego da internet entre continentes passa por cabos submarinos. Sao tubos de fibra optica no fundo do mar, ligando o mundo."}]'::jsonb WHERE id = 'l31';

UPDATE lessons SET content = '[{"type":"heading","value":"HTTP, DNS e IP explicados"},{"type":"paragraph","value":"Essas siglas aparecem o tempo todo quando falamos de internet. Entender o basico ajuda a nao se perder e a perceber quando algo esta seguro ou nao."},{"type":"heading2","value":"Endereco IP: o CEP do computador"},{"type":"paragraph","value":"Todo dispositivo na internet tem um endereco IP — um numero unico, como 192.168.1.1 ou 142.250.185.46. E como o endereco da sua casa: necessario para saber para onde enviar os dados."},{"type":"heading2","value":"DNS: a lista telefonica da internet"},{"type":"paragraph","value":"Ninguem lembra que google.com e 142.250.185.46. O DNS (Domain Name System) traduz nomes legiveis em numeros IP. Quando voce digita um site, o navegador pergunta ao DNS qual e o IP daquele nome e usa esse numero para se conectar."},{"type":"heading2","value":"HTTP e HTTPS: a conversa com o servidor"},{"type":"paragraph","value":"HTTP (HyperText Transfer Protocol) e o protocolo que define como o navegador e o servidor conversam. HTTPS e a versao segura: os dados sao criptografados, entao ninguem no meio do caminho consegue ler. O cadeado na barra de endereco indica HTTPS."},{"type":"callout","title":"Dica","text":"Sempre que possivel, use sites com HTTPS. Evite digitar senhas ou dados sensiveis em paginas que mostram apenas HTTP — elas nao sao criptografadas."}]'::jsonb WHERE id = 'l32';

UPDATE lessons SET content = '[{"type":"heading","value":"O que e cloud computing"},{"type":"paragraph","value":"Cloud computing (computacao em nuvem) e usar recursos de computador pela internet, em vez de ter tudo no seu PC ou servidor local. Armazenamento, processamento e programas podem ficar em data centers distantes e voce acessa quando precisar."},{"type":"heading2","value":"Por que a nuvem importa"},{"type":"paragraph","value":"Antes, empresas precisavam comprar servidores caros e manter uma equipe para cuidar deles. Com a nuvem, voce paga pelo que usa. Precisa de mais espaco? Aumenta. Menos? Reduz. E tudo funciona de qualquer lugar com internet."},{"type":"list","value":["Google Drive e iCloud: armazenam arquivos na nuvem","Netflix e Spotify: stream de video e musica sem baixar","Gmail e Outlook: email na nuvem","Zoom e Google Meet: reunioes online na nuvem"]},{"type":"heading2","value":"On-premise vs nuvem"},{"type":"paragraph","value":"On-premise significa ter servidores na sua empresa — mais controle, mas mais custo e responsabilidade. Na nuvem, outra empresa gerencia os servidores e voce so usa. A maioria das empresas modernas mistura os dois."},{"type":"callout","title":"Dado importante","text":"Segundo pesquisas, mais da metade dos dados corporativos ja esta na nuvem. A tendencia e que esse numero continue crescendo nos proximos anos."}]'::jsonb WHERE id = 'l33';

UPDATE lessons SET content = '[{"type":"heading","value":"IaaS, PaaS e SaaS"},{"type":"paragraph","value":"A nuvem nao e uma coisa so. Existem tres modelos principais de servico: IaaS, PaaS e SaaS. Uma analogia ajuda: pense em moradia."},{"type":"heading2","value":"IaaS: construir sua casa"},{"type":"paragraph","value":"IaaS (Infrastructure as a Service) e como alugar o terreno e a estrutura. Voce recebe maquinas virtuais, redes e armazenamento, mas configura tudo: sistema operacional, banco de dados, aplicacoes. Exemplos: AWS EC2, Google Compute Engine, Azure VMs."},{"type":"heading2","value":"PaaS: apartamento mobiliado"},{"type":"paragraph","value":"PaaS (Platform as a Service) ja entrega o ambiente pronto para rodar sua aplicacao. Voce nao gerencia servidor nem sistema operacional — so coloca seu codigo. Exemplos: Heroku, Google App Engine, Vercel."},{"type":"heading2","value":"SaaS: hotel"},{"type":"paragraph","value":"SaaS (Software as a Service) e como ficar em um hotel: tudo pronto, voce so usa. Acessa pelo navegador ou app, sem instalar nada. Exemplos: Gmail, Slack, Notion, Netflix."},{"type":"callout","title":"Dica","text":"Comece entendendo SaaS — e o que a maioria das pessoas usa no dia a dia. Quem programa costuma usar PaaS e IaaS para hospedar aplicacoes."}]'::jsonb WHERE id = 'l34';

UPDATE lessons SET content = '[{"type":"heading","value":"O que faz um sistema operacional"},{"type":"paragraph","value":"O sistema operacional (SO) e o software mais importante do computador. Ele gerencia o hardware, organiza os arquivos e permite que outros programas rodem. Sem ele, o PC seria um monte de pecas sem instrucoes."},{"type":"heading2","value":"Funcoes principais"},{"type":"paragraph","value":"O SO aloca CPU e RAM para cada programa, controla o disco e as redes, e fornece a interface — grafica (janelas, botoes) ou texto (terminal). Ele tambem permite multitarefa: varios programas rodando ao mesmo tempo."},{"type":"list","value":["Gerenciamento de recursos: divide CPU, RAM e disco entre programas","Interface de usuario: janelas, menus, icones ou linhas de comando","Sistema de arquivos: pastas, arquivos, permissoes","Multitarefa: alternar entre varios programas simultaneamente"]},{"type":"heading2","value":"Por que voce precisa de um SO"},{"type":"paragraph","value":"Programas nao conversam direto com o hardware — seria complicado e inseguro. O SO faz a ponte: recebe pedidos dos programas e traduz para as instrucoes que a placa-mae, o disco e a tela entendem."},{"type":"callout","title":"Reflexao","text":"Pense no celular: o Android ou iOS tambem e um sistema operacional. Ele faz o mesmo trabalho que o Windows ou macOS, so que em formato mobile."}]'::jsonb WHERE id = 'l35';

UPDATE lessons SET content = '[{"type":"heading","value":"Windows vs Linux vs macOS"},{"type":"paragraph","value":"Os tres sistemas operacionais mais usados em desktops e notebooks tem historias e publicos diferentes. Nenhum e objetivamente melhor — depende do que voce precisa e de onde voce esta."},{"type":"heading2","value":"Windows"},{"type":"paragraph","value":"Dominante no mercado, especialmente em escritorios e jogos. A maior compatibilidade com software e hardware do mercado. Muita gente comeca aqui por ser o padrao em muitos PCs."},{"type":"heading2","value":"macOS"},{"type":"paragraph","value":"Sistema da Apple, usado em MacBooks e iMacs. Focado em design, integracao com iPhone e iPad, e publico criativo. Muito usado por desenvolvedores e designers."},{"type":"heading2","value":"Linux"},{"type":"paragraph","value":"Open source, gratuito e altamente customizavel. Dominante em servidores e supercomputadores. Distribuicoes como Ubuntu facilitam para iniciantes. Essencial para quem trabalha com servidores e DevOps."},{"type":"list","value":["Windows: maior compatibilidade, jogos, mercado corporativo","macOS: ecossistema Apple, design, desenvolvimento","Linux: servidores, codigo aberto, DevOps"]},{"type":"callout","title":"Dica","text":"Se quiser trabalhar com TI, experimente os tres. Linux e fundamental para infra e cloud; Windows e comum em empresas; macOS e popular em startups e time de produto."}]'::jsonb WHERE id = 'l36';

UPDATE lessons SET content = '[{"type":"heading","value":"Terminal e linha de comando"},{"type":"paragraph","value":"O terminal e uma janela onde voce digita comandos de texto em vez de clicar em icones. Parece assustador no inicio, mas e uma ferramenta poderosa que desenvolvedores e profissionais de TI usam todos os dias."},{"type":"heading2","value":"Por que usar a linha de comando?"},{"type":"paragraph","value":"Comandos permitem fazer em segundos tarefas que dariam muitos cliques. Automatizacao, scripts e acesso a servidores remotos dependem do terminal. A maioria das ferramentas de programacao tambem funciona melhor por linha de comando."},{"type":"heading2","value":"Comandos basicos"},{"type":"paragraph","value":"Alguns comandos essenciais para comecar:"},{"type":"code","language":"bash","text":"pwd          # mostra em qual pasta voce esta\nls           # lista arquivos e pastas\ncd Documents  # entra na pasta Documents\nmkdir projeto # cria uma pasta chamada projeto"},{"type":"heading2","value":"CLI vs GUI"},{"type":"paragraph","value":"CLI (Command Line Interface) e a linha de comando. GUI (Graphical User Interface) e a interface com janelas e botoes. Ambas sao validas — use a que fizer mais sentido para a tarefa."},{"type":"callout","title":"Mito desfeito","text":"Terminal nao e coisa de hacker. E uma ferramenta comum, como o teclado. Com alguns comandos basicos, voce ja ganha produtividade e entendimento de como o computador organiza arquivos."}]'::jsonb WHERE id = 'l37';

UPDATE lessons SET content = '[{"type":"heading","value":"Senhas seguras e autenticacao"},{"type":"paragraph","value":"Senhas fracas sao a principal porta de entrada para ataques. Aprender boas praticas e usar autenticacao em duas etapas pode evitar grande parte dos problemas."},{"type":"heading2","value":"Boas praticas de senha"},{"type":"paragraph","value":"Use senhas longas (12 caracteres ou mais), com letras, numeros e simbolos. Evite datas, nomes e palavras de dicionario. O mais importante: use uma senha diferente para cada servico. Se uma vazar, as outras continuam seguras."},{"type":"list","value":["Minimo 12 caracteres, idealmente mais","Misture letras, numeros e simbolos","Nao use dados pessoais (nome, data de nascimento)","Senha unica por site ou app"]},{"type":"heading2","value":"Autenticacao em duas etapas (2FA)"},{"type":"paragraph","value":"2FA pede algo alem da senha: um codigo no celular, impressao digital ou chave de seguranca. Mesmo que alguem descubra sua senha, nao consegue entrar sem o segundo fator. Ative 2FA em email, redes sociais e bancos."},{"type":"callout","title":"Dica","text":"Use um gerenciador de senhas (1Password, Bitwarden, LastPass). Ele gera senhas fortes e guarda todas para voce — voce so precisa lembrar de uma senha mestra."}]'::jsonb WHERE id = 'l38';

UPDATE lessons SET content = '[{"type":"heading","value":"Phishing e engenharia social"},{"type":"paragraph","value":"Phishing e um tipo de ataque que usa enganacao para roubar dados. Criminosos se passam por empresas ou pessoas confiaveis e pedem senhas, numeros de cartao ou cliques em links maliciosos. A solucao e desconfiar e verificar."},{"type":"heading2","value":"Como o phishing funciona"},{"type":"paragraph","value":"Voce recebe um email ou mensagem dizendo que sua conta sera bloqueada, que ganhou um premio ou que precisa confirmar dados. O link leva a uma pagina falsa, identica a do banco ou da rede social. Ao digitar a senha, ela vai direto para o atacante."},{"type":"heading2","value":"Sinais de alerta"},{"type":"list","value":["Urgencia extrema: bloqueio em 24h, perda de conta","Links estranhos: verifique o endereco antes de clicar","Erros de portugues ou formatacao estranha","Pedido de senha ou dados por email (empresas serias nao pedem)","Remetente suspeito: @gmail.com se passando por banco"]},{"type":"heading2","value":"Como se proteger"},{"type":"paragraph","value":"Nunca clique em links de emails duvidosos. Digite o endereco do site na mao ou use seus favoritos. Entre em contato com a empresa pelo canal oficial (site, app) se tiver duvida."},{"type":"callout","title":"Mito desfeito","text":"Phishing nao ataca so quem e descuidado. Ataques sao cada vez mais sofisticados e personalizados. Desconfiar e verificar sempre e a melhor defesa."}]'::jsonb WHERE id = 'l39';

UPDATE lessons SET content = '[{"type":"heading","value":"O que e uma rede de computadores"},{"type":"paragraph","value":"Uma rede e um conjunto de dispositivos conectados que trocam informacoes. Seu celular, o roteador de casa e o notebook formam uma rede. A internet e uma rede gigante que liga redes do mundo inteiro."},{"type":"heading2","value":"LAN e WAN"},{"type":"paragraph","value":"LAN (Local Area Network) e uma rede local — sua casa, escritorio ou predio. WAN (Wide Area Network) cobre areas maiores, como cidades ou paises. A internet e a maior WAN do planeta."},{"type":"list","value":["LAN: rede local (casa, empresa, predio)","WAN: rede de longa distancia (cidade, pais, mundo)","Internet: rede de redes, conectando LANs e WANs globalmente"]},{"type":"heading2","value":"Por que redes existem"},{"type":"paragraph","value":"Redes permitem compartilhar arquivos, impressoras e conexao com a internet. Em empresas, funcionarios acessam sistemas internos. Em casa, todos usam o mesmo Wi-Fi. A comunicacao entre dispositivos so e possivel gracas a padroes como TCP/IP."},{"type":"callout","title":"Curiosidade","text":"A internet nasceu como um projeto militar e academico nos EUA nos anos 60. A ideia era criar uma rede que continuasse funcionando mesmo se parte dela fosse destruida."}]'::jsonb WHERE id = 'l40';

UPDATE lessons SET content = '[{"type":"heading","value":"Wi-Fi, roteadores e switches"},{"type":"paragraph","value":"Em casa ou no escritorio, varios dispositivos se conectam a internet. Roteadores e switches organizam o trafego. Wi-Fi e a tecnologia que permite conexao sem fio. Entender o basico ajuda a resolver problemas de conexao."},{"type":"heading2","value":"O que faz o roteador"},{"type":"paragraph","value":"O roteador recebe a internet do seu provedor (via cabo ou fibra) e distribui para os dispositivos. Ele tambem da um endereco IP para cada aparelho na rede local e decide por onde enviar os dados."},{"type":"heading2","value":"Switch: o distribuidor de cabos"},{"type":"paragraph","value":"Um switch conecta varios dispositivos por cabo em uma rede local. Em casa, o roteador ja tem portas de switch embutidas. Em empresas, switches maiores ligam dezenas ou centenas de computadores."},{"type":"heading2","value":"Como o Wi-Fi funciona"},{"type":"paragraph","value":"Wi-Fi usa ondas de radio para transmitir dados pelo ar. O roteador emite um sinal; dispositivos com antena Wi-Fi captam e respondem. Obstaculos (paredes, moveis) podem enfraquecer o sinal. Colocar o roteador em posicao central melhora a cobertura."},{"type":"list","value":["Roteador: conecta sua rede a internet e distribui IPs","Switch: conecta dispositivos por cabo na rede local","Wi-Fi: conexao sem fio via ondas de radio"]},{"type":"callout","title":"Dica","text":"Se a internet esta lenta, reinicie o roteador. Muitos problemas de conexao se resolvem com um simples desligar e ligar."}]'::jsonb WHERE id = 'l41';

UPDATE lessons SET content = '[{"type":"heading","value":"Modelo TCP/IP simplificado"},{"type":"paragraph","value":"Quando voce envia uma mensagem ou acessa um site, os dados nao viajam em um bloco unico. Sao divididos em pacotes que seguem regras do protocolo TCP/IP. O modelo tem quatro camadas que organizam essa comunicacao."},{"type":"heading2","value":"A analogia do correio"},{"type":"paragraph","value":"Imagine enviar uma carta: o conteudo vai no envelope (dados). O envelope tem o endereco de destino (IP). O correio escolhe a rota (rede). E ha regras de como colocar e retirar a carta (protocolos). TCP/IP e o conjunto dessas regras."},{"type":"heading2","value":"As quatro camadas"},{"type":"list","value":["Camada de aplicacao: programas (navegador, email) e protocolos (HTTP, DNS)","Camada de transporte: TCP garante entrega, UDP e mais rapido mas menos confiavel","Camada de rede: IP define enderecos e roteamento dos pacotes","Camada de enlace: envia os bits pelo cabo ou Wi-Fi"]},{"type":"paragraph","value":"Cada camada tem uma funcao. A aplicacao prepara os dados; o transporte divide em pacotes e garante que cheguem; a rede cuida do endereco; a enlace envia fisicamente pelo meio."},{"type":"callout","title":"Curiosidade","text":"TCP significa Transmission Control Protocol. Ele verifica se os pacotes chegaram e pede reenvio se faltar algum. Por isso a web e o email sao confiaveis — mesmo com falhas na rede."}]'::jsonb WHERE id = 'l42';

-- ============================================================
-- SkillBits: Content for lessons l43-l57 (Course c3 - Conceitos Basicos de Programacao)
-- Brazilian Portuguese, no accents. Single quotes doubled in SQL.
-- ============================================================

-- Module m15: O que e programacao
UPDATE lessons SET content = '[{"type":"heading","value":"Linguagens e compiladores"},{"type":"paragraph","value":"Linguagens de programacao sao formas de falar com o computador. Assim como o portugues tem regras de gramatica, cada linguagem tem sua sintaxe e estrutura. O computador so entende zeros e uns — as linguagens traduzem nosso raciocinio para instrucoes que a maquina executa."},{"type":"heading2","value":"Alto nivel vs baixo nivel"},{"type":"paragraph","value":"Linguagens de baixo nivel estao proximas do hardware e exigem controle fino (como Assembly). Linguagens de alto nivel sao mais legiveis e proximas do que escreveriamos em papel — Python, JavaScript e Java sao exemplos. Iniciantes sempre comecam com linguagens de alto nivel."},{"type":"heading2","value":"Compiladores e interpretadores"},{"type":"paragraph","value":"O codigo que escrevemos precisa ser traduzido para a linguagem da maquina. Compiladores transformam o codigo inteiro de uma vez antes de executar (C, Java). Interpretadores traduzem linha a linha enquanto o programa roda (Python, JavaScript)."},{"type":"list","value":["Python: interpretada, simples, muito usada em dados e iniciantes","JavaScript: interpretada, roda no navegador e no servidor","Java: compilada para bytecode, muito usada em empresas","C: compilada, baixo nivel, sistemas e performance"]},{"type":"code","language":"python","text":"# Em Python, isso e quase \"portugues\"\nidade = 18\nif idade >= 18:\n    print(\"Maior de idade\")"},{"type":"callout","title":"Dica","text":"Nao existe melhor linguagem para comecar. Python e JavaScript sao as mais amigaveis. O importante e aprender logica — depois trocar de linguagem fica facil."}]'::jsonb WHERE id = 'l43';

UPDATE lessons SET content = '[{"type":"heading","value":"Seu primeiro Hello World"},{"type":"paragraph","value":"Todo programador comeca com o mesmo ritual: fazer o computador exibir as palavras Hello World. Parece simples, mas esse pequeno programa prova que o ambiente esta configurado e que voce consegue rodar codigo. E um marco simbolico."},{"type":"heading2","value":"A tradicao"},{"type":"paragraph","value":"O Hello World apareceu em livros de programacao nos anos 70 e virou padrao. E o equivalente a aprender a escrever seu nome — o primeiro passo de muitos outros."},{"type":"heading2","value":"Em diferentes linguagens"},{"type":"paragraph","value":"A mesma ideia se expressa de formas diferentes em cada linguagem. Em Python e uma linha. Em JavaScript, outra. A logica e a mesma: imprimir texto na tela."},{"type":"code","language":"python","text":"# Python\nprint(\"Hello World\")"},{"type":"code","language":"javascript","text":"// JavaScript (no navegador ou Node)\nconsole.log(\"Hello World\");"},{"type":"paragraph","value":"Quando voce executa o codigo, o programa transforma sua instrucao em acoes do computador. A funcao print (ou console.log) envia caracteres para a saida — tela, terminal ou arquivo."},{"type":"callout","title":"Experimente","text":"Abra um interpretador online (como repl.it) e digite print(\"Hello World\"). Mude o texto entre aspas. Voce ja esta programando."}]'::jsonb WHERE id = 'l44';

UPDATE lessons SET content = '[{"type":"heading","value":"Como pensar como um programador"},{"type":"paragraph","value":"Programar nao e decorar codigo — e aprender a decompor problemas em passos que a maquina consegue executar. Esse jeito de pensar se chama pensamento computacional."},{"type":"heading2","value":"Os quatro pilares"},{"type":"list","value":["Decomposicao: quebrar um problema grande em partes menores","Reconhecimento de padroes: identificar o que se repete ou e similar","Abstracao: ignorar detalhes irrelevantes e focar no essencial","Design de algoritmos: definir a sequencia de passos para resolver"]},{"type":"heading2","value":"Exemplo do dia a dia: fazer um bolo"},{"type":"paragraph","value":"Voce nao pensa em fazer um bolo inteiro de uma vez. Primeiro separa ingredientes, depois mistura, depois assa. Cada etapa pode ser decomposta de novo (separar ovos, bater claras, etc). E exatamente isso que fazemos com problemas em programacao."},{"type":"heading2","value":"Outro exemplo: GPS"},{"type":"paragraph","value":"O app de rotas recebe origem e destino. Decompoe o caminho em trechos, reconhece padroes de trafego, abstrai detalhes desnecessarios (cor dos carros) e gera um algoritmo: vire a esquerda, siga 2 km, entre na rodovia."},{"type":"code","language":"python","text":"# Pseudocodigo: receita como algoritmo\nenquanto bolo nao assado:\n    aguardar 1 minuto\n    verificar temperatura"},{"type":"callout","title":"Reflexao","text":"Pegue uma tarefa que voce faz todo dia — fazer cafe, arrumar a mochila. Tente escrever os passos como se fosse instrucoes para uma maquina. Voce esta exercitando pensamento computacional."}]'::jsonb WHERE id = 'l45';

-- Module m16: Variaveis e tipos
UPDATE lessons SET content = '[{"type":"heading","value":"O que sao variaveis"},{"type":"paragraph","value":"Variaveis sao como caixas com etiquetas. Voce guarda um valor dentro e da um nome a caixa. Depois pode usar esse nome no codigo para acessar ou alterar o valor. Sem variaveis, programas nao conseguem armazenar informacoes."},{"type":"heading2","value":"Analogia do mundo real"},{"type":"paragraph","value":"Pense em um armario de cozinha: cada gaveta tem etiqueta (acucar, sal) e guarda algo. A variavel idade guarda o numero 25. A variavel nome guarda o texto Maria."},{"type":"heading2","value":"Atribuicao e alteracao"},{"type":"paragraph","value":"Voce atribui um valor com o sinal de igual. O valor pode mudar durante a execucao do programa — por isso se chama variavel."},{"type":"code","language":"python","text":"# Criar variavel\nidade = 18\n\n# Usar e alterar\nidade = idade + 1  # agora idade vale 19"},{"type":"heading2","value":"Bons nomes"},{"type":"list","value":["Use nomes que explicam o conteudo: total_vendas, nome_usuario","Evite letras soltas: x, a (exceto em contadores)","Em Python: minusculas com underscore (snake_case)"]},{"type":"callout","title":"Dica","text":"Nomear bem as variaveis e metade do trabalho. Codigo com nomes claros fica legivel e facil de manter."}]'::jsonb WHERE id = 'l46';

UPDATE lessons SET content = '[{"type":"heading","value":"Tipos de dados: texto, numero e booleano"},{"type":"paragraph","value":"Dados que armazenamos pertencem a tipos diferentes. O computador trata texto, numero e verdadeiro/falso de formas distintas. Saber o tipo e fundamental para evitar erros."},{"type":"heading2","value":"Principais tipos"},{"type":"list","value":["String (str): texto entre aspas — nome, endereco, mensagem","Inteiro (int): numeros sem casa decimal — idade, quantidade","Float: numeros com casa decimal — preco, temperatura","Booleano (bool): True ou False — ligado/desligado, aprovado/reprovado"]},{"type":"code","language":"python","text":"nome = \"Maria\"\nidade = 25\npreco = 19.90\naprovado = True"},{"type":"heading2","value":"O tipo importa"},{"type":"paragraph","value":"Voce nao soma texto com numero diretamente. 5 + 3 da 8, mas \"5\" + \"3\" da \"53\" (concatenacao). O tipo define que operacoes sao validas."},{"type":"code","language":"python","text":"# Isso funciona: soma\nprint(5 + 3)  # 8\n\n# Isso concatena: junta textos\nprint(\"5\" + \"3\")  # 53"},{"type":"callout","title":"Dado importante","text":"Erros de tipo sao comuns em iniciantes. Quando der erro estranho, confira: estou usando o tipo certo? O valor esta entre aspas quando nao deveria?"}]'::jsonb WHERE id = 'l47';

UPDATE lessons SET content = '[{"type":"heading","value":"Operacoes basicas com variaveis"},{"type":"paragraph","value":"Com variaveis criadas, voce pode fazer operacoes: matematicas com numeros, juntar textos, comparar valores. Essas operacoes formam a base da logica dos programas."},{"type":"heading2","value":"Aritmetica"},{"type":"paragraph","value":"Soma, subtracao, multiplicacao e divisao usam os simbolos +, -, * e /. Com inteiros e floats, o resultado segue as regras da matematica."},{"type":"code","language":"python","text":"quantidade = 3\npreco_unitario = 10.50\ntotal = quantidade * preco_unitario\nprint(total)  # 31.5"},{"type":"heading2","value":"Concatenacao"},{"type":"paragraph","value":"Com strings, o + junta textos. Para misturar numero com texto, precisa converter o numero em string primeiro."},{"type":"code","language":"python","text":"nome = \"Joao\"\nidade = 20\nmensagem = nome + \" tem \" + str(idade) + \" anos\""},{"type":"heading2","value":"Comparacao"},{"type":"paragraph","value":"Operadores como ==, !=, >, < retornam True ou False. Sao a base das condicoes que veremos no proximo modulo."},{"type":"code","language":"python","text":"idade = 18\nmaior_idade = idade >= 18  # True\nigual = (idade == 18)  # True"},{"type":"callout","title":"Experimente","text":"Crie variaveis para preco e quantidade de um item. Calcule o total e o total com desconto de 10%. Imprima os resultados."}]'::jsonb WHERE id = 'l48';

-- Module m17: Condicoes
UPDATE lessons SET content = '[{"type":"heading","value":"If, else e else if"},{"type":"paragraph","value":"Programas precisam tomar decisoes. Se o usuario e maior de idade, libera o acesso. Se a nota e maior ou igual a 7, aprovado. If, else e else if (elif) permitem que o codigo siga caminhos diferentes conforme as condicoes."},{"type":"heading2","value":"Analogia: fluxograma"},{"type":"paragraph","value":"Imagine um fluxograma: uma pergunta em losango — \"idade >= 18?\" — com dois caminhos. Sim vai para uma caixa, nao para outra. O if e exatamente isso em codigo."},{"type":"heading2","value":"Sintaxe basica"},{"type":"code","language":"python","text":"if idade >= 18:\n    print(\"Acesso liberado\")\nelse:\n    print(\"Acesso negado\")"},{"type":"heading2","value":"Varias condicoes: elif"},{"type":"paragraph","value":"Quando ha mais de duas opcoes, use elif (else if) para encadear condicoes. A primeira que for verdadeira executa; as demais sao ignoradas."},{"type":"code","language":"python","text":"nota = 8.5\nif nota >= 9:\n    print(\"Excelente\")\nelif nota >= 7:\n    print(\"Aprovado\")\nelif nota >= 5:\n    print(\"Recuperacao\")\nelse:\n    print(\"Reprovado\")"},{"type":"callout","title":"Dica","text":"A indentacao e obrigatoria em Python. O que esta dentro do if precisa estar recuado. Erros de indentacao sao comuns — preste atencao."}]'::jsonb WHERE id = 'l49';

UPDATE lessons SET content = '[{"type":"heading","value":"Operadores de comparacao"},{"type":"paragraph","value":"Para montar condicoes, usamos operadores que comparam valores e retornam True ou False. Conhecer cada um evita erros classicos de iniciantes."},{"type":"heading2","value":"Comparacao entre valores"},{"type":"list","value":["== igual a (cuidado: sao dois sinais de igual)","!= diferente de","> maior que","< menor que",">= maior ou igual","<= menor ou igual"]},{"type":"code","language":"python","text":"x = 10\ny = 5\nprint(x == 10)   # True\nprint(x != y)    # True\nprint(x > y)     # True"},{"type":"heading2","value":"Operadores logicos"},{"type":"paragraph","value":"And junta duas condicoes: ambas precisam ser verdadeiras. Or aceita se pelo menos uma for verdadeira. Not inverte o resultado."},{"type":"code","language":"python","text":"idade = 20\ntem_carteira = True\npode_dirigir = idade >= 18 and tem_carteira  # True\n\n# Or: uma ou outra\nchovendo = False\npegando_sol = True\nbom_dia = chovendo or pegando_sol  # True"},{"type":"callout","title":"Mito desfeito","text":"Um erro comum e usar = em vez de == na comparacao. x = 5 atribui. x == 5 compara. Sao coisas diferentes."}]'::jsonb WHERE id = 'l50';

-- Module m18: Loops
UPDATE lessons SET content = '[{"type":"heading","value":"While e for"},{"type":"paragraph","value":"Muitas vezes precisamos repetir a mesma acao varias vezes. Loops (repeticoes) evitam copiar e colar codigo. While repete enquanto uma condicao for verdadeira. For repete para cada item de uma sequencia (como uma lista)."},{"type":"heading2","value":"While: repete ate a condicao falhar"},{"type":"paragraph","value":"O while verifica a condicao antes de cada repeticao. Se for True, executa o bloco e volta a verificar. Quando a condicao for False, o loop termina."},{"type":"code","language":"python","text":"contador = 0\nwhile contador < 5:\n    print(contador)\n    contador = contador + 1"},{"type":"heading2","value":"For: repete para cada item"},{"type":"paragraph","value":"O for percorre uma sequencia — lista, string, range. Para cada item, executa o bloco. E o loop mais usado quando sabemos quantas vezes repetir ou o que percorrer."},{"type":"code","language":"python","text":"# Repetir 5 vezes\nfor i in range(5):\n    print(i)\n\n# Percorrer lista\nfor fruta in [\"maca\", \"banana\", \"laranja\"]:\n    print(fruta)"},{"type":"heading2","value":"Cuidado: loop infinito"},{"type":"paragraph","value":"Se a condicao do while nunca virar False, o loop nunca termina. Sempre garanta que algo mude dentro do loop para a condicao eventualmente falhar."},{"type":"callout","title":"Dado importante","text":"Loop infinito trava o programa. Se algo parar de responder, interrompa (Ctrl+C no terminal) e verifique se a condicao do while pode virar False."}]'::jsonb WHERE id = 'l51';

UPDATE lessons SET content = '[{"type":"heading","value":"Quando usar cada tipo de loop"},{"type":"paragraph","value":"Escolher o loop certo deixa o codigo mais claro e evita erros. A regra geral: use for quando souber o que percorrer; use while quando a parada depende de uma condicao que nao e contagem."},{"type":"heading2","value":"Use for quando"},{"type":"list","value":["Iterar sobre lista, string ou range","Saber quantas vezes repetir de antemao","Percorrer itens um a um"]},{"type":"heading2","value":"Use while quando"},{"type":"list","value":["O numero de repeticoes e desconhecido","Esperar ate algo acontecer (entrada do usuario, condicao externa)","Contar ate atingir um valor-alvo"]},{"type":"code","language":"python","text":"# For: percorrer lista de nomes\nfor nome in [\"Ana\", \"Bruno\", \"Carla\"]:\n    print(\"Oi, \" + nome)\n\n# While: esperar resposta valida\nresposta = \"\"\nwhile resposta != \"sim\" and resposta != \"nao\":\n    resposta = input(\"Digite sim ou nao: \")"},{"type":"callout","title":"Reflexao","text":"Em muitas situacoes os dois funcionam. Prefira for por ser mais seguro (menos risco de loop infinito) e mais legivel."}]'::jsonb WHERE id = 'l52';

-- Module m19: Funcoes
UPDATE lessons SET content = '[{"type":"heading","value":"Criando e chamando funcoes"},{"type":"paragraph","value":"Funcoes sao blocos de codigo reutilizaveis com um nome. Em vez de repetir o mesmo codigo em varios lugares, voce define uma vez e chama quando precisar. E o principio DRY: Don''t Repeat Yourself."},{"type":"heading2","value":"Analogia: receita"},{"type":"paragraph","value":"Uma receita de bolo e como uma funcao. Voce segue os passos (o codigo dentro da funcao) sempre que quer fazer aquele bolo (chamar a funcao). Os ingredientes podem variar (parametros); o resultado e um bolo (retorno)."},{"type":"heading2","value":"Definir e chamar"},{"type":"code","language":"python","text":"def cumprimentar():\n    print(\"Ola, bem-vindo!\")\n\n# Chamar a funcao\ncumprimentar()\ncumprimentar()  # pode chamar quantas vezes quiser"},{"type":"heading2","value":"Retorno"},{"type":"paragraph","value":"Funcoes podem devolver um valor com return. Esse valor pode ser guardado em variavel ou usado em expressoes."},{"type":"code","language":"python","text":"def calcular_dobro(numero):\n    return numero * 2\n\nresultado = calcular_dobro(5)  # 10"},{"type":"callout","title":"Dica","text":"Funcoes tornam o codigo organizado e testavel. Um programa grande e um conjunto de funcoes pequenas trabalhando juntas."}]'::jsonb WHERE id = 'l53';

UPDATE lessons SET content = '[{"type":"heading","value":"Parametros e retorno"},{"type":"paragraph","value":"Parametros sao as entradas da funcao — valores que voce passa quando chama. O retorno e a saida — o que a funcao devolve. Juntos, parametros e retorno tornam funcoes flexiveis e poderosas."},{"type":"heading2","value":"Parametros como entrada"},{"type":"code","language":"python","text":"def saudar(nome):\n    return \"Ola, \" + nome + \"!\"\n\nmensagem = saudar(\"Maria\")  # \"Ola, Maria!\""},{"type":"heading2","value":"Multiplos parametros e valores default"},{"type":"paragraph","value":"Voce pode ter varios parametros. E possivel definir valor default para quando o chamador nao passar nada."},{"type":"code","language":"python","text":"def calcular_area(largura, altura):\n    return largura * altura\n\nretangulo = calcular_area(4, 5)  # 20\n\ndef cumprimentar(nome, prefixo=\"Ola\"):\n    return prefixo + \", \" + nome\n\ncumprimentar(\"Joao\")      # \"Ola, Joao\"\ncumprimentar(\"Ana\", \"Oi\")  # \"Oi, Ana\""},{"type":"heading2","value":"Exemplo pratico"},{"type":"code","language":"python","text":"def preco_com_desconto(preco, desconto_porcento):\n    valor_desconto = preco * (desconto_porcento / 100)\n    return preco - valor_desconto\n\nfinal = preco_com_desconto(100, 15)  # 85"},{"type":"callout","title":"Experimente","text":"Crie uma funcao media(a, b, c) que recebe tres numeros e retorna a media. Teste com diferentes valores."}]'::jsonb WHERE id = 'l54';

-- Module m20: Primeiro algoritmo
UPDATE lessons SET content = '[{"type":"heading","value":"Planejando o algoritmo"},{"type":"paragraph","value":"Antes de escrever codigo, planeje. Decomponha o problema, escreva em pseudocodigo ou fluxograma, defina os passos. Codificar sem planejar leva a erros e retrabalho."},{"type":"heading2","value":"Decomposicao"},{"type":"paragraph","value":"Quebre o problema em partes menores. Uma calculadora simples: receber dois numeros, receber a operacao, calcular, mostrar resultado. Cada parte vira uma etapa do algoritmo."},{"type":"heading2","value":"Pseudocodigo"},{"type":"paragraph","value":"Pseudocodigo e uma descricao do algoritmo em linguagem proxima do codigo, mas sem sintaxe exata. Ajuda a pensar antes de implementar."},{"type":"code","language":"python","text":"# Pseudocodigo: calculadora simples\n# 1. Pedir primeiro numero\n# 2. Pedir segundo numero\n# 3. Pedir operacao (+ - * /)\n# 4. Se + entao soma\n# 5. Se - entao subtrai\n# 6. ...\n# 7. Mostrar resultado"},{"type":"heading2","value":"Exemplo: fluxo da calculadora"},{"type":"list","value":["Entrada: num1, num2, operador","Processamento: conforme operador, executar conta","Saida: exibir resultado"]},{"type":"callout","title":"Reflexao","text":"Pegue papel e caneta. Escreva os passos de um algoritmo para um problema que voce conhece — por exemplo, verificar se um numero e par. So depois pense em codigo."}]'::jsonb WHERE id = 'l55';

UPDATE lessons SET content = '[{"type":"heading","value":"Implementando passo a passo"},{"type":"paragraph","value":"Com o planejamento pronto, transforme cada passo em codigo. Implemente um pedaco, teste, depois o proximo. Nao tente fazer tudo de uma vez."},{"type":"heading2","value":"Passo 1: entradas"},{"type":"code","language":"python","text":"num1 = float(input(\"Primeiro numero: \"))\nnum2 = float(input(\"Segundo numero: \"))\noperador = input(\"Operacao (+, -, *, /): \")"},{"type":"heading2","value":"Passo 2: logica com condicoes"},{"type":"code","language":"python","text":"if operador == \"+\":\n    resultado = num1 + num2\nelif operador == \"-\":\n    resultado = num1 - num2\nelif operador == \"*\":\n    resultado = num1 * num2\nelif operador == \"/\":\n    resultado = num1 / num2\nelse:\n    resultado = \"Operacao invalida\""},{"type":"heading2","value":"Passo 3: saida"},{"type":"code","language":"python","text":"print(\"Resultado:\", resultado)"},{"type":"paragraph","value":"Juntando tudo, voce tem uma calculadora funcional. Cada bloco foi implementado e testado separadamente. Esse e o jeito de construir programas maiores."},{"type":"callout","title":"Dica","text":"Ao implementar, adicione prints temporarios para ver o valor das variaveis em cada etapa. Isso ajuda a encontrar erros rapidamente."}]'::jsonb WHERE id = 'l56';

UPDATE lessons SET content = '[{"type":"heading","value":"Testando e corrigindo erros"},{"type":"paragraph","value":"Erros fazem parte de programar. O importante e saber ler mensagens de erro, usar estrategias de debug e nao ter medo de quebrar o codigo para aprender."},{"type":"heading2","value":"Tipos de erros"},{"type":"list","value":["Erro de sintaxe: codigo mal escrito (parentese esquecido, dois pontos faltando)","Erro de logica: programa roda mas resultado esta errado","Erro em tempo de execucao: programa quebra durante a execucao (divisao por zero, variavel inexistente)"]},{"type":"heading2","value":"Lendo mensagens de erro"},{"type":"paragraph","value":"A mensagem indica o tipo de erro, o arquivo e a linha. Traceback mostra o caminho das chamadas. Nem sempre o problema esta exatamente na linha indicada — as vezes a causa e anterior."},{"type":"code","language":"python","text":"# Exemplo: NameError\nprint(meu_nome)  # NameError: nome ''meu_nome'' nao definido\n\n# Exemplo: ZeroDivisionError\nprint(10 / 0)  # ZeroDivisionError"},{"type":"heading2","value":"Estrategias de debug"},{"type":"list","value":["Print debugging: imprima variaveis em pontos chave","Leia a mensagem com calma: ela diz o que falta ou esta errado","Reduza o problema: isole o trecho que falha","Execute passo a passo: use um debugger se disponivel"]},{"type":"callout","title":"Mito desfeito","text":"Programadores experientes tambem cometem erros. A diferenca e que eles sabem como encontrar e corrigir rapidamente. Voce aprende debug praticando."}]'::jsonb WHERE id = 'l57';
